when using a class as a dependency, it's possible to add aresponses with class attribute `__responses__` .

```python
import json
from fastapi import FastAPI, Depends

import pydantic

app = FastAPI()


class Response(pydantic.BaseModel):
    reason: str


class User(pydantic.BaseModel):
    id: int
    name: str


class GetUser:
    __responses__ = {401: {"model": Response}}

    async def __call__(self, user_id: int) -> User:
        return User.parse_obj({"id": user_id, "name": "Sum"})


get_user = GetUser()


@app.get("/", responses={200: {"model": User}})
async def get(user: User = Depends(get_user)):
    return user.dict()


@app.get("/v2", responses={200: {"model": User}})
async def get_v2(user: User = Depends(get_user)):
    return user.dict()


print(json.dumps(app.openapi()["paths"]["/"]["get"]["responses"], ensure_ascii=False))
