Or a decorator and UI could be this:

```python
from fastapi import FastAPI
from starlette.requests import Request
# from someplace import depend_decorator


def depend_decorator(responses=None):
    if responses is None:
        responses = {}

    def wrapped(cls):
        cls.__fastapi__ = {'responses': responses}
        return cls

    return wrapped


@depend_decorator(responses={401: {"model": 'Response'}})
class GetUser:
    async def __call__(self, user_id: int):
        return User.parse_obj({"id": user_id, "name": "Sum"})


@depend_decorator(responses={401: {"model": 'Response'}})
async def is_authorized(request: Request):
    pass


if __name__ == '__main__':
    print(GetUser.__fastapi__)
    print(is_authorized.__fastapi__)

```

